insert into bank_questions (question_key, subject_slug, page_id, page_name, source, qtype, marks, snapshot, answer_key)
values
('business:3-2-organisational-structures:exam:182cd390', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'exam', 'mcq', 1, '{"num": "Q35", "question": "Assuming the forecasted figures are correct, the average rate of return for upgrading the robotics will be: [1 mark]", "options": ["A — 5%", "B — 20%", "C — 25%", "D — 125%"], "caseStudy": "A tractor manufacturer wishes to upgrade its robotics at a total cost of £4 million. The cash inflow for each of the next five years is forecasted to be £1 million.", "hint": "Total profit = total income − cost. Average annual profit = total profit ÷ years. ARR = (average annual profit ÷ cost) × 100.", "starter": "Total income = £1m × 5 = £5m. Total profit = £5m − £4m = £1m..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>A — 5%</strong></p></div><div class=\"marks-section\"><h5>Working</h5><ul><li>Total income = £1m × 5 = £5m</li><li>Total profit = £5m − £4m = £1m</li><li>Average annual profit = £1m ÷ 5 = £200,000</li><li>ARR = £200,000 ÷ £4,000,000 × 100 = <strong>5%</strong></li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:3-2-organisational-structures:exam:1df18a21', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'exam', 'mcq', 1, '{"num": "Q36", "question": "The agency''s percentage increase in spending on digital communications from 2017 to 2018 was approximately equal to: [1 mark]", "options": ["A — 48%", "B — 52%", "C — 110%", "D — 210%"], "caseStudy": "A market research agency spent £250,000 on digital communication in 2017 and £525,000 in 2018.", "hint": "The spending has more than doubled, so the answer must be more than 100%. Use the 2017 figure as the original.", "starter": "Percentage change = (change ÷ original) × 100 = (£275,000 ÷ £250,000) × 100 = ..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>C — 110%</strong></p></div><div class=\"marks-section\"><h5>Working</h5><ul><li>Change = £525,000 − £250,000 = £275,000</li><li>% change = £275,000 ÷ £250,000 × 100 = <strong>110%</strong></li></ul></div><div class=\"marks-section\"><h5>Examiner''s Comment</h5><p>This had the greatest proportion of incorrect answers of all the MCQ questions. The figures have more than doubled, so the answer must be greater than 100%. A common misconception is dividing by the new value instead of the original.</p></div>", "modelAnswer": ""}'::jsonb),
('business:3-2-organisational-structures:exam:9f050750', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'exam', 'mcq', 1, '{"num": "Q38", "question": "What was the market stall''s revenue? [1 mark]", "options": ["A — £200", "B — £1,000", "C — £1,200", "D — £2,200"], "caseStudy": "A market stall sells bread for £1 a loaf and cookies for 60p each. Yesterday 1,000 loaves of bread and 2,000 cookies were sold.", "hint": "Revenue = price × quantity for each product. Then add the two totals together.", "starter": "Total revenue = (bread revenue) + (cookie revenue) = ..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>D — £2,200</strong></p></div><div class=\"marks-section\"><h5>Working</h5><ul><li>Bread revenue = £1 × 1,000 = £1,000</li><li>Cookie revenue = £0.60 × 2,000 = £1,200</li><li>Total revenue = £1,000 + £1,200 = <strong>£2,200</strong></li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:3-2-organisational-structures:exam:cb3c0ecf', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'exam', 'mcq', 1, '{"num": "Q39", "question": "Gross profit margin is: [1 mark]", "options": ["A — a computerised method of production", "B — a financial ratio", "C — a pricing method", "D — a variable cost"], "hint": "Think about what category gross profit margin belongs to — it''s a way of measuring financial performance.", "starter": "Gross profit margin is classified as..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>B — a financial ratio</strong></p></div><div class=\"marks-section\"><h5>Why</h5><p>Gross profit margin expresses gross profit as a proportion (ratio) of revenue. It is used to assess a business''s financial performance — it is not a method of production, pricing strategy, or cost.</p></div>", "modelAnswer": ""}'::jsonb),
('business:3-2-organisational-structures:exam:f27b4b6f', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'exam', 'mcq', 1, '{"num": "Q40", "question": "Which one of the following must be true for this business? [1 mark]", "options": ["A — The business cannot pay its short term debts", "B — The business has made a loss", "C — The business has revenues that are greater than its costs", "D — The business is operating below its break even level"], "caseStudy": "A business has a net profit margin of 8%.", "hint": "A positive net profit margin means the business is profitable. What does that tell you about revenues vs costs?", "starter": "A net profit margin of 8% means that..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>C — The business has revenues that are greater than its costs</strong></p></div><div class=\"marks-section\"><h5>Why</h5><p>A positive net profit margin of 8% means the business is making a profit — so revenues must exceed total costs. It does not tell us about short-term debt or whether it is above break-even in terms of units.</p></div>", "modelAnswer": ""}'::jsonb),
('business:3-2-organisational-structures:exam:660a7f00', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'exam', 'mcq', 1, '{"num": "Q41", "question": "What is the approximate increase between 2015 and 2016 in Jimco plc''s production costs? [1 mark]", "options": ["A — 0.9%", "B — 1.6%", "C — 7.0%", "D — 7.5%"], "caseStudy": "The production costs for Jimco plc were £21.3 million in 2015 and £22.9 million in 2016.", "hint": "Percentage change = (change ÷ original) × 100. Use the 2015 figure as the original.", "starter": "Percentage increase = (£1.6m ÷ £21.3m) × 100 = ..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>D — 7.5%</strong></p></div><div class=\"marks-section\"><h5>Working</h5><ul><li>Change = £22.9m − £21.3m = £1.6m</li><li>% change = £1.6m ÷ £21.3m × 100 = <strong>7.5%</strong></li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:3-2-organisational-structures:exam:e7104661', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'exam', 'mcq', 1, '{"num": "Q43", "question": "In 2018 Pluck and Grow Ltd made: [1 mark]", "options": ["A — a loss of £52,000", "B — a loss of £42,000", "C — a profit of £16,000", "D — a profit of £26,000"], "caseStudy": "Financial data for Pluck and Grow Ltd in 2018:\n• Total revenue: £68,000\n• Total labour costs: £26,000\n• Total material costs: £16,000\n• Other costs: £10,000", "hint": "Add up all costs, then subtract from revenue.", "starter": "Total costs = £26,000 + £16,000 + £10,000 = ..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>C — a profit of £16,000</strong></p></div><div class=\"marks-section\"><h5>Working</h5><ul><li>Total costs = £26,000 + £16,000 + £10,000 = £52,000</li><li>Profit = £68,000 − £52,000 = <strong>£16,000</strong></li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:3-2-organisational-structures:exam:ed12fcd3', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'exam', 'mcq', 1, '{"num": "Q44", "question": "The data shows that: [1 mark]", "options": ["A — the company prefers to transport its goods by air", "B — the company''s transport costs have fallen year on year", "C — GLU plc spent more than £1.25 million on transport costs in 2018", "D — GLU plc transports more goods by rail than by road"], "caseStudy": "Transport costs of Global Logistics United plc (GLU plc) for the last five years:\n\nBy road: 2014 £150k | 2015 £160k | 2016 £170k | 2017 £180k | 2018 £190k\nBy rail: 2014 £350k | 2015 £370k | 2016 £390k | 2017 £410k | 2018 £430k\nBy air: 2014 £600k | 2015 £620k | 2016 £635k | 2017 £640k | 2018 £650k", "hint": "Add up all three transport modes for 2018 and compare to £1.25 million.", "starter": "Total transport costs in 2018 = £190k + £430k + £650k = ..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>C — GLU plc spent more than £1.25 million on transport costs in 2018</strong></p></div><div class=\"marks-section\"><h5>Working</h5><ul><li>2018 total: £190,000 + £430,000 + £650,000 = £1,270,000 > £1.25m ✓</li><li>Costs are rising (not falling), so B is wrong</li><li>Higher spending on air does not mean preference, so A is unconfirmed</li><li>Higher costs by rail doesn''t confirm more goods transported, so D is unconfirmed</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:3-2-organisational-structures:exam:4abfeab8', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'exam', 'mcq', 1, '{"num": "Q45", "question": "What was Exobike''s gross profit margin? [1 mark]", "options": ["A — 68%", "B — 147%", "C — £4,704", "D — £14,700"], "caseStudy": "Exobike made a gross profit of £9,996 from selling 42 exercise bikes at £350 each.", "hint": "First calculate total revenue (price × quantity). Then GPM = (gross profit ÷ revenue) × 100. Note: two options are not even percentages, so you can eliminate them.", "starter": "Total revenue = 42 × £350 = ..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>A — 68%</strong></p></div><div class=\"marks-section\"><h5>Working</h5><ul><li>Revenue = 42 × £350 = £14,700</li><li>GPM = £9,996 ÷ £14,700 × 100 = <strong>68%</strong></li></ul></div><div class=\"marks-section\"><h5>Examiner''s Comment</h5><p>Candidates could eliminate C and D immediately as they are monetary values, not percentages. Even without doing the full calculation, knowledge that a GPM is a percentage narrows the answer to A or B — and 68% is a realistic margin while 147% is not possible.</p></div>", "modelAnswer": ""}'::jsonb),
('business:3-2-organisational-structures:mcq:f826bf1e', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'mcq', 'mcq', 1, '{"question": "A business with a tall organisational structure will have:", "options": ["A high market share", "Short chains of command", "Lots of distribution channels", "Multiple layers of authority"]}'::jsonb, '{"answer": 3, "explain": "A tall structure is defined by having many layers of authority from top to bottom. This creates long chains of command — not short ones. Market share and distribution channels are unrelated to structure."}'::jsonb),
('business:3-2-organisational-structures:mcq:11f9dd3a', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'mcq', 'mcq', 1, '{"question": "A clothing designer may choose to flatten its organisational structure to reduce the:", "options": ["Need for innovation and change", "Creativity of its garment designers", "Independence of its fabric buyers", "Time it takes to respond to changes in fashion"]}'::jsonb, '{"answer": 3, "explain": "A flat structure has fewer layers, so communication is faster. This means the business can respond more quickly to changes in fashion trends. Flattening does NOT reduce creativity — it usually enhances it."}'::jsonb),
('business:3-2-organisational-structures:mcq:a6f284d1', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'mcq', 'mcq', 1, '{"question": "The span of control of the Production Manager (who has 3 Production Supervisors reporting directly to them) is:", "options": ["63", "21", "3", "1"]}'::jsonb, '{"answer": 2, "explain": "The span of control is the number of people who report DIRECTLY to a manager. Only the 3 Production Supervisors report directly to the Production Manager — not the 20 workers under each supervisor."}'::jsonb),
('business:3-2-organisational-structures:mcq:f3b60fe4', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'mcq', 'mcq', 1, '{"question": "A business may choose to have a flat organisational structure because it:", "options": ["Reduces the likelihood of mistakes in vertical communication", "Slows down the organisation''s response to changes in the market", "Lengthens the organisation''s chain of command", "Gives employees more opportunities for promotion"]}'::jsonb, '{"answer": 0, "explain": "Fewer layers means fewer people for a message to pass through — so there are fewer opportunities for it to be changed or distorted. This reduces mistakes in vertical (upward/downward) communication."}'::jsonb),
('business:3-2-organisational-structures:mcq:7b8a064f', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'mcq', 'mcq', 1, '{"question": "A flat organisational structure has:", "options": ["Narrow spans of control", "No specific person in overall charge", "A long chain of command", "Few levels of authority"]}'::jsonb, '{"answer": 3, "explain": "A flat structure is defined by having FEW levels (layers) of authority — perhaps only 2 or 3. It has WIDE (not narrow) spans of control and SHORTER (not longer) chains of command."}'::jsonb),
('business:3-2-organisational-structures:mcq:2134ac05', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'mcq', 'mcq', 1, '{"question": "Who is a director''s subordinate?", "options": ["A manager", "A shareholder", "A supplier", "A customer"]}'::jsonb, '{"answer": 0, "explain": "Subordinates are the workers that a line manager (or director) is responsible for and has authority over. Managers report to directors, making them subordinates. Customers, shareholders and suppliers are external parties."}'::jsonb),
('business:3-2-organisational-structures:mcq:16ae2db6', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'mcq', 'mcq', 1, '{"question": "Which of the following is an advantage to a fruit farm of employing temporary workers to pick the fruit?", "options": ["The number of workers employed can be varied according to the season", "Discrimination laws do not apply because the work is only for a few weeks", "Induction training will not be required because the work is not permanent", "Workers are likely to be more committed to their jobs and pick more fruit"]}'::jsonb, '{"answer": 0, "explain": "The key advantage of temporary workers is flexibility — the farm can increase or decrease the number of workers to match seasonal demand for fruit picking. Discrimination laws ALWAYS apply, and induction training is still needed."}'::jsonb),
('business:3-2-organisational-structures:mcq:d5ebd61e', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'mcq', 'mcq', 1, '{"question": "Which one of the following is a benefit to a flower shop of employing extra temporary sales staff on Valentine''s Day?", "options": ["Workers can be paid less than the minimum wage", "More customers can be served", "Roses can be sold for cheaper prices", "The flowers will be fresher"]}'::jsonb, '{"answer": 1, "explain": "With more staff, the shop can serve more customers during the peak demand on Valentine''s Day — reducing queues and improving customer service. Temporary staff cannot be paid below the minimum wage."}'::jsonb),
('business:3-2-organisational-structures:mcq:0ce483b7', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'mcq', 'mcq', 1, '{"question": "The main financial benefit of delayering for Leigh Hire Ltd (removing two supervisor roles at £35,000 each, giving the Service Manager a £10,000 pay rise) is a saving of:", "options": ["£60,000 per year", "£35,000 per year", "£70,000 per year", "£80,000 per year"]}'::jsonb, '{"answer": 0, "explain": "Two roles at £35,000 = £70,000 saved. Less the £10,000 increase to the Service Manager = net saving of £60,000 per year. This is the key financial application figure for the Leigh Hire case study."}'::jsonb),
('business:3-2-organisational-structures:mcq:8e60254d', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'mcq', 'mcq', 1, '{"question": "What is the mean average managerial span of control at POD Ltd, which has 5 managers each managing: 6 accounts clerks, 4 clerical assistants, 28 production workers, 5 sales reps, and 3 HR assistants?", "options": ["10.2", "9.2", "8.5", "7.7"]}'::jsonb, '{"answer": 2, "explain": "Total subordinates = 6+4+28+5+3 = 46. Divided by 5 managers = 9.2 per manager. But the Managing Director also manages 5 managers. Mean average across all 6 managers = (46+5)/6 = 8.5."}'::jsonb),
('business:3-2-organisational-structures:tf:d8a1501b', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'tf', 'tf', 1, '{"question": "A tall organisational structure has a wide span of control."}'::jsonb, '{"answer": false, "explain": "Tall structures have a NARROW span of control — each manager supervises fewer people. FLAT structures have a wide span of control."}'::jsonb),
('business:3-2-organisational-structures:tf:747f3f13', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'tf', 'tf', 1, '{"question": "Delayering means adding more layers to an organisational structure."}'::jsonb, '{"answer": false, "explain": "Delayering means REMOVING layers to make the structure flatter. It reduces the number of management levels, usually to save money and speed up communication."}'::jsonb),
('business:3-2-organisational-structures:tf:2a6e9afa', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'tf', 'tf', 1, '{"question": "The span of control of a manager with 3 supervisors, each managing 20 workers, is 3."}'::jsonb, '{"answer": true, "explain": "Correct. Span of control only counts DIRECT reports. The 3 supervisors report directly to the manager. The 60 workers report to their supervisors — not directly to the manager."}'::jsonb),
('business:3-2-organisational-structures:tf:93ea9b12', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'tf', 'tf', 1, '{"question": "Part-time workers have fewer employment rights than full-time workers."}'::jsonb, '{"answer": false, "explain": "This is a common misconception. Part-time employees have EXACTLY THE SAME employment rights as full-time workers. The number of hours worked does not affect their rights."}'::jsonb),
('business:3-2-organisational-structures:tf:9d5c1408', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'tf', 'tf', 1, '{"question": "A flat organisational structure is best suited to large, non-creative businesses."}'::jsonb, '{"answer": false, "explain": "Flat structures suit creative businesses (e.g. game design) and smaller businesses. Large, non-creative businesses with clear tasks tend to suit TALL structures with defined authority."}'::jsonb),
('business:3-2-organisational-structures:tf:a7860172', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'tf', 'tf', 1, '{"question": "Delegation means giving a subordinate responsibility for a task while the manager remains ultimately accountable."}'::jsonb, '{"answer": true, "explain": "Correct. Delegation gives the subordinate authority and responsibility to make certain decisions, but the manager is still ultimately responsible for the outcome."}'::jsonb),
('business:3-2-organisational-structures:tf:aa47718f', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'tf', 'tf', 1, '{"question": "Working from home always increases worker productivity."}'::jsonb, '{"answer": false, "explain": "It CAN increase productivity (less commute stress, flexible hours) but NOT always. Distractions at home (children, TV) and social isolation can reduce productivity. The effect varies by individual and role."}'::jsonb),
('business:3-2-organisational-structures:tf:1fe931b7', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'tf', 'tf', 1, '{"question": "Leigh Hire Ltd''s delayering plan would save £70,000 in wages per year."}'::jsonb, '{"answer": false, "explain": "The saving is £60,000. Two roles at £35,000 each = £70,000 saved. MINUS the £10,000 pay rise for the Service Manager = net saving of £60,000 per year."}'::jsonb),
('business:3-2-organisational-structures:tf:432ba1b2', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'tf', 'tf', 1, '{"question": "A zero-hours worker is not guaranteed any work hours each week."}'::jsonb, '{"answer": true, "explain": "Correct. Zero-hours contracts mean the worker has a contract but is not guaranteed any hours. They are called in when needed, sometimes at very short notice."}'::jsonb),
('business:3-2-organisational-structures:tf:f4ab7a5a', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'tf', 'tf', 1, '{"question": "Autocratic leaders tend to prefer flat organisational structures."}'::jsonb, '{"answer": false, "explain": "Autocratic leaders prefer TALL structures because they give more control — narrow spans of control mean managers have fewer people to supervise, and the long chain of command keeps authority centralised at the top."}'::jsonb),
('business:3-2-organisational-structures:tf:a51682ec', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'tf', 'tf', 1, '{"question": "Hybrid working means working entirely from home, with no time in the office."}'::jsonb, '{"answer": false, "explain": "Hybrid working means working PART of the time at home AND part in the office — not entirely from home. Working entirely from home is simply ''working from home''."}'::jsonb),
('business:3-2-organisational-structures:tf:6c50cdeb', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'tf', 'tf', 1, '{"question": "A self-employed person receives holiday pay from a client business."}'::jsonb, '{"answer": false, "explain": "Self-employed workers are NOT employees. They do not receive holiday pay, sick pay or employer pension contributions from the businesses they work for. This is one of the key disadvantages of self-employment."}'::jsonb),
('business:3-2-organisational-structures:tf:580c0d8a', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'tf', 'tf', 1, '{"question": "JD Wetherspoon uses flexible contracts with shifts varying from 4 to 10 hours based on demand."}'::jsonb, '{"answer": true, "explain": "Correct. JD Wetherspoon uses flexible-working contracts where shifts vary between 4 and 10 hours to match demand — more staff during busy lunch and evening periods, fewer during quiet mornings."}'::jsonb),
('business:3-2-organisational-structures:tf:44b95794', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'tf', 'tf', 1, '{"question": "Beautiful Buds plc would make a net annual saving of £1 million from its delayering plan, after removing Middle Managers and Team Leaders and adding supervisors."}'::jsonb, '{"answer": true, "explain": "Correct. £600k (Middle Managers) + £700k (Team Leaders) = £1.3m saved. Less £300k (10 new supervisors) = £1m net annual saving. The £200k redundancy is a one-off cost."}'::jsonb),
('business:3-2-organisational-structures:learn:537a7f35', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'learn', 'mcq', 1, '{"readingTitle": "Core Terminology", "reading": "<ul>\n<li><strong>Organisational structure</strong> — how people and departments are arranged within a business; the hierarchy of employees</li>\n<li><strong>Organisation chart</strong> — a diagram showing how workers are organised and who is in charge of whom</li>\n<li><strong>Layers</strong> — the number of levels of authority in a chain of command</li>\n<li><strong>Authority</strong> — the power to make decisions and tell other workers what to do</li>\n<li><strong>Line manager</strong> — the person directly in charge of other workers; the person a worker is responsible to</li>\n<li><strong>Subordinates</strong> — workers that a line manager is responsible for</li>\n<li><strong>Chain of command</strong> — the path of authority along which instructions pass, from the CEO downwards</li>\n<li><strong>Span of control</strong> — the number of employees/subordinates that report directly to a manager</li>\n<li><strong>Delegation</strong> — when a manager gives a subordinate authority and responsibility to make certain decisions (the manager remains ultimately responsible)</li>\n<li><strong>Accountability</strong> — the responsibility a person has for a job; they take blame for what goes wrong as well as credit for what goes well</li>\n<li><strong>Delayering</strong> — when a business reduces the number of layers in its structure, making it flatter</li>\n<li>\n     <a href=\"extra/org_chartV2.html\" target=\"_blank\" rel=\"noopener noreferrer\"> Our School Organisation chart </a> </li>\n</ul>", "question": "When a manager delegates a task to a subordinate, who remains ultimately responsible for the outcome?", "options": ["The subordinate''s line manager''s line manager", "No one — responsibility disappears once delegated", "Only the subordinate carrying out the task", "The manager who delegated it"]}'::jsonb, '{"answer": 3, "explain": "The glossary states that when a manager delegates, they give authority and responsibility to a subordinate but remain ultimately responsible."}'::jsonb),
('business:3-2-organisational-structures:learn:01d3e297', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'learn', 'mcq', 1, '{"readingTitle": "Tall vs Flat Organisational Structures", "reading": "<p><strong>Tall structure:</strong> Many layers; narrow span of control. Suited to large organisations (e.g. hospitals) and non-creative businesses with clear, limited tasks (e.g. building companies).</p>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">✓ Advantages of Tall</div>\n<div class=\"pro-item\">Clear lines of communication and authority</div>\n<div class=\"pro-item\">Easier supervision — fewer direct reports per manager</div>\n<div class=\"pro-item\">Workers are clear who they are responsible to</div>\n<div class=\"pro-item\">Promotion opportunities motivate workers</div>\n</div>\n<div>\n<div class=\"col-head\">✗ Disadvantages of Tall</div>\n<div class=\"con-item\">Subordinates feel too controlled — can stifle motivation</div>\n<div class=\"con-item\">Slower communications — many layers to pass through</div>\n<div class=\"con-item\">Messages more likely to be distorted through many people</div>\n<div class=\"con-item\">Workers may only talk to immediate colleagues</div>\n</div>\n</div>\n<p style=\"margin-top:12px;\"><strong>Flat structure:</strong> Few layers (2–3); wide span of control. Suited to creative businesses (e.g. game design) and smaller businesses where workers feeling valued matters.</p>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">✓ Advantages of Flat</div>\n<div class=\"pro-item\">Workers feel trusted — managers must delegate widely</div>\n<div class=\"pro-item\">Easier to share ideas — more likely to know bosses directly</div>\n<div class=\"pro-item\">Faster communication — fewer layers</div>\n<div class=\"pro-item\">Messages less likely to be changed or distorted</div>\n<div class=\"pro-item\">Saves money — fewer layers of managers needed</div>\n</div>\n<div>\n<div class=\"col-head\">✗ Disadvantages of Flat</div>\n<div class=\"con-item\">Lines of communication not always clear</div>\n<div class=\"con-item\">Few promotion opportunities — can reduce motivation</div>\n<div class=\"con-item\">Managers may have too many people to look after</div>\n</div>\n</div>", "question": "According to the notes, which type of business is a tall structure best suited to?", "options": ["Businesses wanting to save money on management wages", "Businesses that want the fastest possible communication", "Small creative businesses like game design studios that value flexibility", "Large organisations that have very clear limited tasks"]}'::jsonb, '{"answer": 3, "explain": "The notes state tall structures suit large organisations (e.g. hospitals) and non-creative businesses with clear, limited tasks (e.g. building companies)."}'::jsonb),
('business:3-2-organisational-structures:learn:e816d0b4', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'learn', 'mcq', 1, '{"readingTitle": "Why Businesses Choose Different Structures", "reading": "<p>The structure adopted depends on several factors:</p>\n<ul>\n<li><strong>Scale of business</strong> — large businesses usually require hierarchical structures for clear control; small businesses find this less important</li>\n<li><strong>Function</strong> — organised by functional areas (Marketing, Finance, Production, HR)</li>\n<li><strong>Product</strong> — organised by different product lines</li>\n<li><strong>Place</strong> — organised by locations (e.g. regional offices)</li>\n<li><strong>Nature of the business</strong> — creative businesses suit flat structures; clear-task businesses may suit tall</li>\n<li><strong>Type of leadership</strong> — autocratic leaders prefer tall structures to maintain control</li>\n<li><strong>Effective communication</strong> — whichever structure results in the best communication for that specific organisation</li>\n</ul>\n<p><strong>Delayering:</strong> Businesses reduce layers to save money and gain the advantages of flat structures — faster communication, more delegated authority. e.g. Leigh Hire Ltd saved £60,000 per year by removing two supervisor roles.</p>", "question": "What does ''delayering'' mean in the context of organisational structure?", "options": ["Reducing the number of layers in a structure to make it flatter", "Changing from a product-based to a place-based structure", "Increasing the number of management layers for better control", "Replacing autocratic leaders with democratic ones"]}'::jsonb, '{"answer": 0, "explain": "The card defines delayering as businesses reducing layers to save money and gain flat-structure advantages, citing Leigh Hire Ltd saving £60,000/year."}'::jsonb),
('business:3-2-organisational-structures:learn:3c4c58b7', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'learn', 'mcq', 1, '{"readingTitle": "Full-time, Part-time & Temporary Working", "reading": "<p><strong>Full-time:</strong> 35+ hours per week. Worker permanently available; business pays even when no work is being done.</p>\n<p><strong>Part-time:</strong> Under 35 hours per week. Part-time employees have the SAME employment rights as full-time workers.</p>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">Part-time — Business</div>\n<div class=\"pro-item\">Can use workers at peak times; saves overtime; more recruitment choice</div>\n<div class=\"con-item\">Higher training costs per head; more supervision time needed</div>\n</div>\n<div>\n<div class=\"col-head\">Part-time — Worker</div>\n<div class=\"pro-item\">Can work when it suits (school hours, students, semi-retired)</div>\n<div class=\"con-item\">Lower income; uncertainty if hours are variable; inconvenient split shifts</div>\n</div>\n</div>\n<p style=\"margin-top:10px;\"><strong>Temporary working:</strong> Short period/fixed-term contract (e.g. seasonal work in agriculture or Christmas retail). Workers can be used when needed without long-term commitment. Risk: lack of commitment, training costs wasted.</p>\n<p><strong>Zero-hours contract:</strong> A person has a contract but is not guaranteed any hours. Informed when needed, sometimes at short notice.</p>", "question": "What best describes a zero-hours contract?", "options": ["A contract for exactly 35 hours per week", "A contract that removes all employment rights", "A contract only available to full-time staff", "A contract with no guaranteed number of hours"]}'::jsonb, '{"answer": 3, "explain": "The notes define a zero-hours contract as one where a person has a contract but is not guaranteed any hours, being informed when needed."}'::jsonb),
('business:3-2-organisational-structures:learn:65f3718a', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'learn', 'mcq', 1, '{"readingTitle": "Flexible Working, Home & Hybrid Working", "reading": "<p><strong>Flexible working:</strong> Working partly at the workplace and partly elsewhere, or at variable times. Includes flexi-time (working weekly hours in fewer days) and shift working.</p>\n<p><strong>Working from home:</strong> Completing work in the home. <strong>Hybrid working:</strong> Part of the time at home, part in an office.</p>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">Home/Hybrid — Business</div>\n<div class=\"pro-item\">Saves on office space/rent; increased productivity; wider recruitment (don''t need to live locally)</div>\n<div class=\"con-item\">Harder to monitor work; communication can be poor; technology costs</div>\n</div>\n<div>\n<div class=\"col-head\">Home/Hybrid — Worker</div>\n<div class=\"pro-item\">Saves time and money on travel; less stress; can work around family commitments</div>\n<div class=\"con-item\">Distractions at home; social isolation; higher utility bills</div>\n</div>\n</div>\n<p style=\"margin-top:10px;\"><strong>Case study — Wokingham Council:</strong> Introduced flexible/hot-desking working; saved money on office space; productivity improved and absenteeism fell. Success depended on ICT (calls transferred to mobile phones).</p>\n<p><strong>Case study — BP:</strong> Moved 6,000 staff to hybrid model (3 days office, 2 days home) to reduce high London office costs.</p>", "question": "What distinguishes ''hybrid working'' from simply ''working from home''?", "options": ["Hybrid working removes the need for any office space", "Hybrid working is only available to managers", "Hybrid splits time between home and the office itself", "Hybrid working means fewer hours are worked overall"]}'::jsonb, '{"answer": 2, "explain": "The card defines working from home as being completed entirely at home, while hybrid working means part of the time at home and part in an office."}'::jsonb),
('business:3-2-organisational-structures:learn:f15d0c1f', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'learn', 'mcq', 1, '{"readingTitle": "Self-Employment & Mobile Working", "reading": "<p><strong>Self-employment:</strong> When people work in their own business, selling their work to buyers (consumers or other businesses). Examples: plumbers, electricians, taxi drivers. In early 2020, 5.03 million people were self-employed (15.3% of UK working population).</p>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">✓ Pros of Self-Employment</div>\n<div class=\"pro-item\">Being your own boss; high motivation</div>\n<div class=\"pro-item\">Can earn more by working harder/faster</div>\n<div class=\"pro-item\">Freedom to choose work and clients</div>\n</div>\n<div>\n<div class=\"col-head\">✗ Cons of Self-Employment</div>\n<div class=\"con-item\">No guaranteed income</div>\n<div class=\"con-item\">No holiday pay, sick pay or employer pension contributions</div>\n<div class=\"con-item\">Loss of employment rights (e.g. unfair dismissal protection)</div>\n</div>\n</div>\n<p style=\"margin-top:10px;\"><strong>Working while mobile:</strong> Working while travelling or on the move. Made easier by technology — email, video calls, cloud software.</p>\n<p><strong>Benefit for business:</strong> EDF used self-employed workers for Hinkley Point C construction — only paid for specialist skills when needed, keeping costs lower and reducing long-term commitments.</p>", "question": "Which of these is a genuine drawback of being self-employed, according to the notes?", "options": ["Automatic protection against unfair dismissal", "No holiday pay, sick pay or pension contributions", "A guaranteed weekly income regardless of work done", "Being told exactly what work to do by a line manager"]}'::jsonb, '{"answer": 1, "explain": "The notes list no holiday pay, sick pay or employer pension contributions as a key con of self-employment, alongside no guaranteed income and loss of rights like unfair dismissal protection."}'::jsonb),
('business:3-2-organisational-structures:learn:01fec437', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'learn', 'mcq', 1, '{"readingTitle": "Case Studies Linked to Concepts", "reading": "<p><strong>Griffin Engineering Ltd:</strong> Functional hierarchy with 5 layers. Illustrates chain of command, span of control (Sales Manager = 5), and delegation (Production Manager → Stock Control Manager).</p>\n<p><strong>J.J. Jewellery:</strong> Small family business, flat structure (3 layers). Myiesha (Shop Manager) has span of control of 5. Mix of 2 full-time and 2 part-time shop assistants.</p>\n<p><strong>Leigh Hire Ltd (delayering):</strong> Removed two supervisor roles (£35k each) and gave work to Service Manager (+£10k). Net saving: £60,000/year. Risk: wider span of control for Service Manager may worsen communication.</p>\n<p><strong>JD Wetherspoon:</strong> 38,000 workers; flexible contracts with shifts varying 4–10 hours based on demand. Currently short of 6,000 staff — suggests flexible/insecure contracts may deter applicants.</p>\n<p><strong>HSBC:</strong> Over 70% of call centre employees now work from home permanently. Benefits: lower overhead costs, productivity gains. Risks: monitoring difficulties, technology costs.</p>\n<p><strong>Beautiful Buds plc (delayering):</strong> Removing Middle Managers (£600k saving) and Team Leaders (£700k saving) saves £1.3m. Adding 10 supervisors costs £300k. Net annual saving: £1m (after £200k one-off redundancy cost).</p>", "question": "In the Griffin Engineering Ltd case study, the Sales Manager''s span of control is 5. What does this figure represent?", "options": ["The number of years the Sales Manager has worked there", "Employees who report directly to the Sales Manager", "The total number of employees in the whole business", "The number of layers in the chain of command"]}'::jsonb, '{"answer": 1, "explain": "The card uses Griffin Engineering to illustrate span of control as the number of direct reports to a manager, here the Sales Manager''s span of 5."}'::jsonb),
('business:3-2-organisational-structures:misc:f484cd40', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> The organisational structure and the organisation chart are the same thing.</p><p><strong>✅ The correct idea:</strong> They are different. The STRUCTURE is the actual hierarchy — how people and authority are arranged. The CHART is the DIAGRAM that shows that structure visually. You can have a structure without a chart, but a chart represents the structure.</p>", "question": "What is the correct relationship between an organisational structure and an organisation chart?", "options": ["They are two words for exactly the same thing", "A business can have a chart but never a structure", "The chart is a diagram representing the structure", "The chart is the actual hierarchy, and the structure is only the diagram"]}'::jsonb, '{"answer": 2, "explain": "The card clarifies the structure is the actual hierarchy while the chart is the diagram that represents it visually — they are not identical."}'::jsonb),
('business:3-2-organisational-structures:misc:91353b5c', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Part-time workers have fewer employment rights than full-time workers.</p><p><strong>✅ The correct idea:</strong> Part-time employees have EXACTLY THE SAME employment rights as full-time workers. The number of hours worked does not affect the type or permanency of their employment rights. This is a very common misconception that loses marks.</p>", "question": "How do the employment rights of part-time workers compare to full-time workers?", "options": ["Part-time workers have fewer rights because they work fewer hours", "They are exactly the same", "Part-time workers have rights only if on a permanent contract", "Part-time workers only gain full rights after one year"]}'::jsonb, '{"answer": 1, "explain": "The card corrects the common misconception, stating part-time employees have exactly the same employment rights as full-time workers."}'::jsonb),
('business:3-2-organisational-structures:misc:651f4d59', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> A wide span of control means a manager has few people to supervise.</p><p><strong>✅ The correct idea:</strong> A WIDE span means a manager has MANY subordinates reporting to them directly. A NARROW span means fewer subordinates. Wide span = flat structure; narrow span = tall structure. Students frequently confuse these.</p>", "question": "What does a WIDE span of control mean for a manager?", "options": ["The manager has very few people to supervise", "The manager has many direct-reporting subordinates", "The manager works in a tall structure", "The manager has no authority to make decisions"]}'::jsonb, '{"answer": 1, "explain": "The card explains a wide span means many direct subordinates (linked to flat structures), while a narrow span means few (linked to tall structures)."}'::jsonb),
('business:3-2-organisational-structures:misc:01385d56', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Delayering always makes a business better.</p><p><strong>✅ The correct idea:</strong> Delayering has BOTH benefits AND drawbacks. Benefits: saves wages, faster communication, more delegation. Drawbacks: fewer promotion opportunities for workers (reduces motivation), wider span of control may overwhelm remaining managers, and communication may actually get worse if the span becomes too wide. Evaluation is always required.</p>", "question": "Which statement best reflects the mark-scheme expectation when discussing delayering?", "options": ["It is always beneficial and should never be criticised", "It always increases the number of management layers", "It only affects wages and has no impact on communication", "It has both benefits and drawbacks, weighed together"]}'::jsonb, '{"answer": 3, "explain": "The card stresses delayering has both benefits (saved wages, faster communication) and drawbacks (fewer promotions, wider span risk), so evaluation is always required."}'::jsonb),
('business:3-2-organisational-structures:misc:8aacd69c', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Span of control includes all the workers below a manager, not just direct reports.</p><p><strong>✅ The correct idea:</strong> Span of control ONLY counts the people who report DIRECTLY to that manager — not everyone in the layers below. For example, a Production Manager with 3 supervisors (each managing 20 workers) has a span of control of 3, not 63.</p>", "question": "A Production Manager has 3 supervisors, each managing 20 workers. What is the Production Manager''s span of control?", "options": ["3", "20", "63", "60"]}'::jsonb, '{"answer": 0, "explain": "Span of control only counts people reporting directly to that manager, so the Production Manager''s span is 3, not the 63 total workers below."}'::jsonb),
('business:3-2-organisational-structures:misc:5ccfead2', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Flexible/home working is always beneficial for both businesses and workers.</p><p><strong>✅ The correct idea:</strong> Flexible/home working has BOTH benefits and drawbacks for BOTH parties. For workers: benefits include saving travel costs and flexibility, but drawbacks include social isolation and home distractions. For businesses: benefits include reduced office costs and productivity gains, but drawbacks include monitoring difficulties and technology costs. Never state it is ''always good.''</p>", "question": "Which statement correctly describes flexible/home working according to the notes?", "options": ["It benefits businesses but always harms workers", "It is always beneficial for workers and businesses alike", "It has no effect on office costs", "It has both benefits and drawbacks for workers and firms"]}'::jsonb, '{"answer": 3, "explain": "The card warns against saying flexible/home working is ''always good'', explaining it carries benefits and drawbacks for both workers and businesses."}'::jsonb),
('business:3-2-organisational-structures:misc:91861ca5', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> The chain of command and the span of control are the same concept.</p><p><strong>✅ The correct idea:</strong> They are different. The CHAIN OF COMMAND is the LINE of authority from top to bottom (vertical path of instructions). The SPAN OF CONTROL is the NUMBER of subordinates one manager has (horizontal count). Confusing these terms in exam answers loses marks.</p>", "question": "What is the key difference between chain of command and span of control?", "options": ["Span of control only applies to flat structures", "They are different names for the same concept", "Chain of command counts subordinates; span of control shows the line of authority", "Chain of command is the line of authority; span is the number of subordinates"]}'::jsonb, '{"answer": 3, "explain": "The card distinguishes chain of command (the vertical path of authority) from span of control (the horizontal count of direct subordinates)."}'::jsonb),
('business:3-2-organisational-structures:tips:703ecb75', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'tips', 'mcq', 1, '{"readingTitle": "Most Repeated Question Type — Analyse one benefit/drawback of a structure (3 marks)", "reading": "Structure: (U) Explain the benefit (e.g. ''faster communication in a flat structure''). (APP) Link to the specific business in the case study (e.g. ''this means Nessa can respond quickly to the needs in the six stores''). (AN) Show the business impact (e.g. ''this could reverse the declining sales revenue''). Always chain: feature → effect on THIS business → business consequence.", "question": "For a 3-mark ''analyse one benefit of a structure'' question, what should the answer chain together?", "options": ["The feature, its link to the business, and the consequence", "A judgement on which structure is best without explanation", "Two unrelated advantages listed separately", "Only a definition of the structure with no context"]}'::jsonb, '{"answer": 0, "explain": "The tip explains the answer should chain: feature → effect on THIS business → business consequence (U, APP, AN)."}'::jsonb),
('business:3-2-organisational-structures:tips:e497f357', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'tips', 'mcq', 1, '{"readingTitle": "Most Repeated Question Type — Recommend which structure is most appropriate (3 marks)", "reading": "Make a clear recommendation (1 mark). Justify it with TWO contextual reasons from the case study for full marks. Example: ''Miles Ahead should use a flat structure (1) so that decisions can be made more quickly to reverse the fall in sales revenue since 2018 (CONT) and so that employees in the six stores feel trusted and motivated (CONT).''", "question": "To gain full marks recommending which structure is most appropriate (3 marks), what must the answer include beyond the recommendation itself?", "options": ["Two contextual reasons justifying the choice made", "Only one reason, since two would be repetitive", "A list of every possible structure with no justification", "A calculation of the exact span of control"]}'::jsonb, '{"answer": 0, "explain": "The tip states a clear recommendation (1 mark) must be justified with TWO contextual reasons from the case study for full marks."}'::jsonb),
('business:3-2-organisational-structures:tips:7c982c18', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'tips', 'mcq', 1, '{"readingTitle": "Most Repeated Question Type — State one advantage/disadvantage of a way of working (1 mark)", "reading": "These short questions appear very frequently. Make sure you know ONE clear advantage AND disadvantage of: temporary working, flexible working, working from home, and zero-hours contracts — from BOTH the business AND the worker perspective. Never write ''saves money'' without specifying what costs are saved.", "question": "For a 1-mark ''state one advantage/disadvantage'' question about a way of working, what should be avoided?", "options": ["Writing ''saves money'' without specifying what costs are saved", "Keeping the answer short and direct", "Naming a specific way of working such as flexible working", "Giving the answer from the business''s perspective"]}'::jsonb, '{"answer": 0, "explain": "The tip warns never to write ''saves money'' without specifying what costs are actually saved."}'::jsonb),
('business:3-2-organisational-structures:tips:eb02fc8d', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'tips', 'mcq', 1, '{"readingTitle": "7-Mark Evaluate Question — Evaluate whether a business should continue with a way of working", "reading": "Structure: APP x2 (use case study evidence twice — e.g. specific staff numbers, shift lengths). AN x2 (show the business impact of each point). EVAL x3 (judgement: should they continue? + 2 justified reasons using context). For JD Wetherspoon: link flexible contracts to cost control AND the staff shortage of 6,000 workers.", "question": "What is the recommended mark-scheme structure for a 7-mark ''evaluate whether to continue with a way of working'' question?", "options": ["APP x2, AN x2, EVAL x3", "One long paragraph with no clear structure", "Only a definition followed by one example", "K x1, U x1, with no application or evaluation"]}'::jsonb, '{"answer": 0, "explain": "The tip specifies structuring the answer as APP x2 (case study evidence), AN x2 (business impact), then EVAL x3 (judgement and two justified reasons)."}'::jsonb),
('business:3-2-organisational-structures:tips:3de6247f', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'tips', 'mcq', 1, '{"readingTitle": "9-Mark Discuss Question — Discuss whether to change organisational structure (9 marks)", "reading": "For Beautiful Buds: K (define delayering) → U (explain the process) → APP x2 (use the NUMBERS: £600k + £700k saving, £300k extra supervisor costs, £200k redundancy) → AN x2 (show business impact of savings AND risks) → EVAL x3 (overall judgement with net saving of £1m per year, long-term vs short-term). ALWAYS use the specific figures provided.", "question": "For the 9-mark ''discuss whether to change organisational structure'' question on Beautiful Buds, why is it important to use the specific figures (£600k, £700k, £300k, £200k)?", "options": ["Because only the final net saving figure needs to be mentioned", "Because K marks require quoting numbers instead of definitions", "Because the figures are not actually relevant to the answer", "Because APP marks need the case study numbers as evidence"]}'::jsonb, '{"answer": 3, "explain": "The tip stresses the APP x2 stage must use the specific numbers provided (savings and costs) to gain application marks, alongside K, U, AN and EVAL."}'::jsonb),
('business:3-2-organisational-structures:tips:09b82c5d', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'tips', 'mcq', 1, '{"readingTitle": "Calculation Warning — Span of control calculations", "reading": "Span of control = ONLY direct reports. If a Production Manager has 3 supervisors, span = 3 (not 3 + 20×3 = 63). Mean average span: add up ALL subordinates across ALL managers, then divide by the number of managers. For POD Ltd: 46 total subordinates + 5 managers = 51 total. 6 managers total. 51 ÷ 6 = 8.5.", "question": "How is the mean average span of control calculated across a business?", "options": ["Divide the number of managers by the number of layers", "Multiply the number of layers by the number of subordinates", "Add together the spans of only the most senior managers", "Add subordinates across managers, then divide by total"]}'::jsonb, '{"answer": 3, "explain": "The tip explains the mean average span is found by adding all subordinates across all managers, then dividing by the number of managers, as shown in the POD Ltd example (51 ÷ 6 = 8.5)."}'::jsonb),
('business:3-2-organisational-structures:tips:fb175812', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'tips', 'mcq', 1, '{"readingTitle": "Examiner Warning — Always evaluate delayering with BOTH sides", "reading": "Never say delayering is simply ''good because it saves money.'' Examiners expect both sides: savings vs. motivation risk (no promotion opportunities), faster communication vs. potential overload of remaining managers. Use the specific financial figures (e.g. £60,000 saving for Leigh Hire) for application marks. Conclude with a justified judgement.", "question": "According to the examiner warning, why should you never simply say delayering is ''good because it saves money''?", "options": ["Because delayering never actually saves any money", "Because only application marks are available for this topic", "Because savings should never be mentioned in an answer about delayering", "Examiners expect both sides weighed, like savings versus lost promotions"]}'::jsonb, '{"answer": 3, "explain": "The warning states examiners expect both sides — savings vs motivation risk and faster communication vs potential manager overload — followed by a justified judgement."}'::jsonb),
('business:3-2-organisational-structures:tips:f1de4748', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'tips', 'mcq', 1, '{"readingTitle": "Key Examiner Warning — Do NOT say part-time workers have fewer rights", "reading": "This is repeatedly flagged by examiners. Part-time workers have EXACTLY THE SAME employment rights as full-time workers. Writing otherwise will lose marks. Similarly, zero-hours workers cannot be paid below the minimum wage — a common misconception. Discrimination laws apply to ALL workers regardless of contract type.", "question": "Besides the part-time rights misconception, what other common error does this examiner warning highlight about zero-hours workers?", "options": ["The mistaken belief they can be paid below minimum wage", "The mistaken belief that zero-hours workers have no contract at all", "The mistaken belief that zero-hours workers cannot be dismissed", "The mistaken belief that zero-hours contracts are illegal in the UK"]}'::jsonb, '{"answer": 0, "explain": "The warning notes zero-hours workers cannot legally be paid below minimum wage, correcting a common misconception, and that discrimination laws apply to all workers regardless of contract type."}'::jsonb),
('business:3-2-organisational-structures:fib:8be468d1', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'fib', 'fib', 2, '{"question": "The number of subordinates that report directly to a manager is called the _____ of control. A tall structure has a _____ span of control.", "blankOptions": {"B1": ["creative", "span", "same", "part-time"], "B2": ["35", "layers", "narrow", "authority"]}}'::jsonb, '{"blanks": {"B1": "span", "B2": "narrow"}}'::jsonb),
('business:3-2-organisational-structures:fib:29169d6e', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'fib', 'fib', 2, '{"question": "When a business removes layers from its structure it is called _____, which usually saves _____ and speeds up communication.", "blankOptions": {"B1": ["tall", "flat", "delayering", "same"], "B2": ["part-time", "flat", "layers", "money"]}}'::jsonb, '{"blanks": {"B1": "delayering", "B2": "money"}}'::jsonb),
('business:3-2-organisational-structures:fib:7f90fca2', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'fib', 'fib', 2, '{"question": "A _____ structure has few layers and a wide span of control, making it suited to _____ businesses where fast communication matters.", "blankOptions": {"B1": ["narrow", "tall", "flat", "flexible"], "B2": ["creative", "productivity", "boss", "holiday"]}}'::jsonb, '{"blanks": {"B1": "flat", "B2": "creative"}}'::jsonb),
('business:3-2-organisational-structures:fib:d0eb00bb', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'fib', 'fib', 2, '{"question": "Full-time working means working _____ hours or more per week, while part-time workers have the _____ employment rights as full-time workers.", "blankOptions": {"B1": ["35", "tall", "flat", "narrow"], "B2": ["layers", "authority", "same", "narrow"]}}'::jsonb, '{"blanks": {"B1": "35", "B2": "same"}}'::jsonb),
('business:3-2-organisational-structures:fib:0eda7d01', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'fib', 'fib', 2, '{"question": "Working from home saves businesses money on office _____ and can increase worker _____, but makes it harder to monitor staff.", "blankOptions": {"B1": ["span", "delayering", "space", "wide"], "B2": ["productivity", "control", "money", "flexible"]}}'::jsonb, '{"blanks": {"B1": "space", "B2": "productivity"}}'::jsonb),
('business:3-2-organisational-structures:fib:30279e8e', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'fib', 'fib', 2, '{"question": "A self-employed worker earns no _____ pay or sick pay from an employer, but benefits from being their own _____ and potentially earning more.", "blankOptions": {"B1": ["same", "holiday", "layers", "space"], "B2": ["tall", "same", "boss", "span"]}}'::jsonb, '{"blanks": {"B1": "holiday", "B2": "boss"}}'::jsonb),
('business:3-2-organisational-structures:match:55ef407c', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Span of control”?", "options": ["Working part of the time at home and part of the time in an office", "A contract where the worker is not guaranteed any hours and is called in when needed, sometimes at short notice", "The number of subordinates who report directly to a manager", "When a business reduces the number of layers in its organisational structure, making it flatter"]}'::jsonb, '{"answer": 2, "explain": "“Span of control” means: The number of subordinates who report directly to a manager"}'::jsonb),
('business:3-2-organisational-structures:match:2da57c3e', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Chain of command”?", "options": ["The number of subordinates who report directly to a manager", "Working part of the time at home and part of the time in an office", "An organisational structure with many layers and a narrow span of control, suited to large or non-creative businesses", "The path of authority along which instructions are passed, from the CEO downwards"]}'::jsonb, '{"answer": 3, "explain": "“Chain of command” means: The path of authority along which instructions are passed, from the CEO downwards"}'::jsonb),
('business:3-2-organisational-structures:match:d697549c', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Delegation”?", "options": ["The path of authority along which instructions are passed, from the CEO downwards", "When a business reduces the number of layers in its organisational structure, making it flatter", "A contract where the worker is not guaranteed any hours and is called in when needed, sometimes at short notice", "The process where a manager gives a subordinate authority to make certain decisions, while the manager remains ultimately responsible"]}'::jsonb, '{"answer": 3, "explain": "“Delegation” means: The process where a manager gives a subordinate authority to make certain decisions, while the manager remains ultimately responsible"}'::jsonb),
('business:3-2-organisational-structures:match:2920587b', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Delayering”?", "options": ["Working part of the time at home and part of the time in an office", "The number of subordinates who report directly to a manager", "The process where a manager gives a subordinate authority to make certain decisions, while the manager remains ultimately responsible", "When a business reduces the number of layers in its organisational structure, making it flatter"]}'::jsonb, '{"answer": 3, "explain": "“Delayering” means: When a business reduces the number of layers in its organisational structure, making it flatter"}'::jsonb),
('business:3-2-organisational-structures:match:905cee20', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Tall structure”?", "options": ["An organisational structure with many layers and a narrow span of control, suited to large or non-creative businesses", "The number of subordinates who report directly to a manager", "The path of authority along which instructions are passed, from the CEO downwards", "An organisational structure with few layers and a wide span of control, suited to creative or smaller businesses"]}'::jsonb, '{"answer": 0, "explain": "“Tall structure” means: An organisational structure with many layers and a narrow span of control, suited to large or non-creative businesses"}'::jsonb),
('business:3-2-organisational-structures:match:e111f824', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Flat structure”?", "options": ["An organisational structure with few layers and a wide span of control, suited to creative or smaller businesses", "The path of authority along which instructions are passed, from the CEO downwards", "A contract where the worker is not guaranteed any hours and is called in when needed, sometimes at short notice", "An organisational structure with many layers and a narrow span of control, suited to large or non-creative businesses"]}'::jsonb, '{"answer": 0, "explain": "“Flat structure” means: An organisational structure with few layers and a wide span of control, suited to creative or smaller businesses"}'::jsonb),
('business:3-2-organisational-structures:match:aa213dfb', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Zero-hours contract”?", "options": ["A contract where the worker is not guaranteed any hours and is called in when needed, sometimes at short notice", "An organisational structure with many layers and a narrow span of control, suited to large or non-creative businesses", "Working part of the time at home and part of the time in an office", "The number of subordinates who report directly to a manager"]}'::jsonb, '{"answer": 0, "explain": "“Zero-hours contract” means: A contract where the worker is not guaranteed any hours and is called in when needed, sometimes at short notice"}'::jsonb),
('business:3-2-organisational-structures:match:a9114858', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Hybrid working”?", "options": ["An organisational structure with many layers and a narrow span of control, suited to large or non-creative businesses", "The path of authority along which instructions are passed, from the CEO downwards", "A contract where the worker is not guaranteed any hours and is called in when needed, sometimes at short notice", "Working part of the time at home and part of the time in an office"]}'::jsonb, '{"answer": 3, "explain": "“Hybrid working” means: Working part of the time at home and part of the time in an office"}'::jsonb),
('business:3-3-communication-in-business:exam:2a75cf14', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'exam', 'mcq', 1, '{"num": "Q1", "question": "Which of these statements is FALSE?", "options": ["Digital communication involves the electronic transfer of information", "Mobile phones, computers and tablets are ways in which information can be transferred electronically", "Digital communication is always better than non-digital communication such as meetings", "Digital communication has been a major force behind the globalisation of business activity"], "hint": "Look for the word ''always'' — this is usually the signal that a statement is too absolute to be true.", "starter": "Digital communication is not always better because..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>C — Digital communication is always better than non-digital communication</strong></p></div>\n<div class=\"marks-section\"><h5>Why</h5><p>This statement is false because non-digital methods such as face-to-face meetings have distinct advantages: immediate two-way feedback, body language, discussion, and problem-solving. Digital communication cannot always replicate these. The word ''always'' makes this an absolute claim that is clearly incorrect.</p></div>", "modelAnswer": ""}'::jsonb),
('business:3-3-communication-in-business:exam:1701df10', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'exam', 'mcq', 1, '{"num": "Q2", "question": "What is a benefit to a patient of receiving communication from their hospital doctor by email rather than by letter?", "options": ["Doctors receive confirmation of receipt when the email is opened", "Emails can contain hyperlinks to further information about treatments", "Emails save money by reducing stationery, printing, and postal costs", "Multiple medical appointments can be sent out at the same time"], "hint": "Think about this from the PATIENT''S perspective — what helps the patient, not the doctor or the hospital.", "starter": "A benefit to the patient of email over letter is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>B — Emails can contain hyperlinks to further information about treatments</strong></p></div>\n<div class=\"marks-section\"><h5>Why</h5><p>This is the only option that benefits the PATIENT specifically. Hyperlinks allow patients to access additional information about their condition or treatment — which helps them understand their healthcare. Options A, C and D are benefits to the hospital/doctor, not the patient.</p></div>", "modelAnswer": ""}'::jsonb),
('business:3-3-communication-in-business:exam:e5023e26', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'exam', 'mcq', 1, '{"num": "Q5 (a)", "question": "Explain the term ''digital communications''. [1 mark]", "options": ["Sending letters and leaflets to customers", "The electronic exchange of information using ICT", "Face-to-face communication between people", "The use of meetings and presentations in business"], "caseStudy": "Amazon is one the best examples of a business that benefited from the revolution in digital communication. It started as a book seller in the 1990s. By selling books online, it did not need shops on the high street. Books were stored in warehouses and delivered directly to customers at reduced prices. Amazon sold to customers all over the USA then expanded globally. It uses robots in some of its warehouses — once received, the order is communicated directly to a robot which retrieves the product.", "hint": "Think about what makes communication ''digital'' — what technology is involved?", "starter": "Digital communication is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>B — The electronic exchange of information using ICT</strong></p></div>\n<div class=\"marks-section\"><h5>Why</h5><p>Digital communication is specifically the electronic exchange of information using ICT. This includes email, websites, faxes, social media, and programming machines/robots to respond to data. Letters and face-to-face communication are non-digital.</p></div>", "modelAnswer": ""}'::jsonb),
('business:3-3-communication-in-business:mcq:2a75cf14', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'mcq', 'mcq', 1, '{"question": "Which of these statements is FALSE?", "options": ["Digital communication is always better than non-digital communication", "Digital communication has been a major force behind the globalisation of business", "Digital communication involves the electronic transfer of information", "Mobile phones, computers and tablets can transfer information electronically"]}'::jsonb, '{"answer": 0, "explain": "Digital communication is NOT always better than non-digital. Face-to-face meetings, for example, allow immediate feedback, body language, and discussion that digital communication cannot always replicate. ''Always'' is a giveaway that this statement is false."}'::jsonb),
('business:3-3-communication-in-business:mcq:fc7f3a36', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'mcq', 'mcq', 1, '{"question": "Which of the following is NOT an advantage of meetings?", "options": ["The sender can check immediately whether the receiver has understood the message", "It is a way of avoiding confrontation when the message is given", "The sender of the message can always be seen and heard by the receiver", "There will usually be a record of formal meetings in the form of minutes"]}'::jsonb, '{"answer": 1, "explain": "Avoiding confrontation is an advantage of WRITTEN communication, not meetings. Meetings involve face-to-face interaction, which can actually make confrontation more likely. Written communication allows a message to be delivered without direct conflict."}'::jsonb),
('business:3-3-communication-in-business:mcq:05db713a', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'mcq', 'mcq', 1, '{"question": "Which of the following is NOT true about digital communication?", "options": ["The development of digital communication has benefited all workers", "It has helped to increase globalisation of business", "It has made it possible for some workers to work at home", "It has increased competition often leading to lower prices"]}'::jsonb, '{"answer": 0, "explain": "Digital communication has NOT benefited ALL workers. While many have gained new opportunities and flexibility, others have lost their jobs as productivity improved and automation replaced roles. Workers have also had to undergo retraining."}'::jsonb),
('business:3-3-communication-in-business:mcq:19b60a8d', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'mcq', 'mcq', 1, '{"question": "In 2021, Instagram had 1 billion users. 300 million were aged 18–24. The percentage of Instagram users in the 18–24 bracket is:", "options": ["33%", "30%", "13%", "3%"]}'::jsonb, '{"answer": 1, "explain": "300 million ÷ 1,000 million × 100 = 30%. This shows how Instagram is heavily used by young people, making it a strong platform for businesses targeting under-35 customers."}'::jsonb),
('business:3-3-communication-in-business:mcq:c3e20403', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'mcq', 'mcq', 1, '{"question": "What is a disadvantage for a business of using digital communication?", "options": ["It is a slow method of communication", "Worldwide communication is not possible", "The technology on which it relies can fail", "Pictures and videos cannot be shared"]}'::jsonb, '{"answer": 2, "explain": "Technology failure is a real risk of digital communication — systems can crash, lose data, or be disrupted by cyber-attacks or power cuts. Options A, B, and D are all incorrect: digital communication is fast, can share rich media, and enables worldwide reach."}'::jsonb),
('business:3-3-communication-in-business:mcq:cc15be9b', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'mcq', 'mcq', 1, '{"question": "A market research agency spent £250,000 on digital communication in 2017 and £525,000 in 2018. The percentage increase was approximately:", "options": ["52%", "48%", "110%", "210%"]}'::jsonb, '{"answer": 2, "explain": "Percentage change = (New − Old) ÷ Old × 100 = (525,000 − 250,000) ÷ 250,000 × 100 = 275,000 ÷ 250,000 × 100 = 110%. A common mistake is dividing by the NEW value — always divide by the ORIGINAL value."}'::jsonb),
('business:3-3-communication-in-business:mcq:6cdb9f65', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'mcq', 'mcq', 1, '{"question": "Which of these is an example of digital communication?", "options": ["A letter", "A face-to-face interview", "A website", "A magazine"]}'::jsonb, '{"answer": 2, "explain": "A website is digital communication — it uses ICT to exchange information electronically. A face-to-face interview is verbal, a letter is written (non-digital), and a magazine is print media."}'::jsonb),
('business:3-3-communication-in-business:mcq:8cafd0d2', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'mcq', 'mcq', 1, '{"question": "A frozen food manufacturer urgently needs its maintenance contractor to repair its freezers. Which is the best method?", "options": ["Send a letter by first class post", "Post a message on its website saying it has problems with freezers", "Produce a presentation to explain the problem", "Telephone the maintenance contractor and explain the problem"]}'::jsonb, '{"answer": 3, "explain": "The phone is the best method here because it is URGENT and requires TWO-WAY communication so the contractor can ask questions and clarify details immediately. A letter is too slow, a website post is not directed at the contractor, and a presentation is unnecessary for an urgent repair."}'::jsonb),
('business:3-3-communication-in-business:mcq:c75a4620', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'mcq', 'mcq', 1, '{"question": "Which one of the following is NOT a potential benefit of improving communication between a business and its customers?", "options": ["Greater market share", "Better customer service", "Higher chances of survival", "Increased risk"]}'::jsonb, '{"answer": 3, "explain": "Increased risk is a potential consequence of poor communication, not better communication. Improved communication leads to better customer service, greater market share, and higher chances of survival — all business benefits."}'::jsonb),
('business:3-3-communication-in-business:mcq:89c8d7f3', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'mcq', 'mcq', 1, '{"question": "A farmer urgently needs a spare part for a tractor but doesn''t know its name or code. Which is the best communication method?", "options": ["Send a letter showing a sketch of the part", "Upload a video to the farm website showing how important the tractor is", "Post on social media that the tractor has broken down", "Send an email to the parts supplier attaching a photo of the part"]}'::jsonb, '{"answer": 3, "explain": "An email with a photo of the part is best because it is FAST (urgent situation), VISUAL (no need to know the name/code), and sent directly to the supplier. A letter is too slow, social media doesn''t reach the supplier, and a website video is irrelevant."}'::jsonb),
('business:3-3-communication-in-business:tf:d23852f2', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'tf', 'tf', 1, '{"question": "Digital communication is always better than non-digital methods such as meetings."}'::jsonb, '{"answer": false, "explain": "FALSE — this is a key examiner trap. Meetings allow immediate feedback, body language, and real-time discussion. Digital communication has disadvantages such as technology failure and inability to convey body language."}'::jsonb),
('business:3-3-communication-in-business:tf:e7c0e60c', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'tf', 'tf', 1, '{"question": "One-way communication is useful for situations where a response is not required."}'::jsonb, '{"answer": true, "explain": "Correct. One-way communication is suited to giving information to large numbers of people — e.g. a tannoy announcement, an advertising leaflet, or a broadcast email — where no reply is needed."}'::jsonb),
('business:3-3-communication-in-business:tf:db784b53', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'tf', 'tf', 1, '{"question": "Horizontal communication takes place between people on different levels of the hierarchy."}'::jsonb, '{"answer": false, "explain": "HORIZONTAL communication is between people at the SAME level of the hierarchy. Communication between DIFFERENT levels is VERTICAL (either upward or downward)."}'::jsonb),
('business:3-3-communication-in-business:tf:908d3528', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'tf', 'tf', 1, '{"question": "The development of digital communication has benefited all workers."}'::jsonb, '{"answer": false, "explain": "FALSE and a key examiner point. Some workers lost jobs as productivity increased and automation replaced roles. Others had to retrain. Blockbuster staff, shelf-label workers, and bank tellers are examples of roles reduced by digital change."}'::jsonb),
('business:3-3-communication-in-business:tf:c3be5d0b', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'tf', 'tf', 1, '{"question": "A website operates 24 hours a day, seven days a week."}'::jsonb, '{"answer": true, "explain": "Correct. This is a key advantage of websites — they allow customers to access information and place orders at any time, without the business needing staff available."}'::jsonb),
('business:3-3-communication-in-business:tf:32fc4ff1', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'tf', 'tf', 1, '{"question": "Email is the best method of communication for ALL business situations."}'::jsonb, '{"answer": false, "explain": "The best method depends on the situation: purpose, audience, urgency, and sensitivity. For example, a phone call is better for urgent issues, and face-to-face is better for sensitive HR discussions. No single method is always best."}'::jsonb),
('business:3-3-communication-in-business:tf:0b7c60d0', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'tf', 'tf', 1, '{"question": "Formal communication uses official channels such as letters, official meetings, and reports."}'::jsonb, '{"answer": true, "explain": "Correct. Formal communication follows set procedures and official channels. It contrasts with informal communication, which occurs outside these channels (e.g. chatting at lunch)."}'::jsonb),
('business:3-3-communication-in-business:tf:fbd5593b', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'tf', 'tf', 1, '{"question": "Social media can only be used for external communication with customers."}'::jsonb, '{"answer": false, "explain": "Social media can also be used for INTERNAL communication. Groups of workers can use platforms to message each other, arrange meetings, share ideas, and receive instructions — especially useful across multiple locations."}'::jsonb),
('business:3-3-communication-in-business:tf:c59c757a', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'tf', 'tf', 1, '{"question": "A disadvantage of verbal communication is that there is no permanent record unless minutes or a recording are made."}'::jsonb, '{"answer": true, "explain": "Correct. This is a key disadvantage of verbal communication. If a dispute arises about what was said, there is no evidence unless someone took minutes or a recording was made."}'::jsonb),
('business:3-3-communication-in-business:tf:eaeccd06', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'tf', 'tf', 1, '{"question": "The percentage increase from £250,000 to £525,000 is approximately 110%."}'::jsonb, '{"answer": true, "explain": "Correct. (£525,000 − £250,000) ÷ £250,000 × 100 = £275,000 ÷ £250,000 × 100 = 110%. Since the value more than doubled, the answer must exceed 100%."}'::jsonb),
('business:3-3-communication-in-business:tf:b9e36720', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'tf', 'tf', 1, '{"question": "Blockbuster is an example of a business that thrived due to the digital communication revolution."}'::jsonb, '{"answer": false, "explain": "Blockbuster FAILED because of the digital communication revolution. Netflix''s online streaming service replaced Blockbuster''s DVD rental model. Blockbuster was too slow to adapt and went out of business."}'::jsonb),
('business:3-3-communication-in-business:tf:04402fd9', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'tf', 'tf', 1, '{"question": "The Chatsworth Estate accountant case study shows that digital technology allowed one accountant to handle 20 times the business revenue."}'::jsonb, '{"answer": true, "explain": "Correct. Michael Isherwood started as the only accountant. Business revenues grew by twenty times but when he retired, there was only one other accountant alongside him. Digital technology transformed productivity in the finance function."}'::jsonb),
('business:3-3-communication-in-business:tf:2c7c4a0f', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'tf', 'tf', 1, '{"question": "For a recommendation question, simply choosing one method scores full marks."}'::jsonb, '{"answer": false, "explain": "Choosing one method gives only 1 mark. For the other 2 marks, students must provide a COMPARATIVE justification — explaining why the chosen method is better THAN the other method — ideally using case study context for full marks."}'::jsonb),
('business:3-3-communication-in-business:tf:a01d70a1', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'tf', 'tf', 1, '{"question": "Amazon''s use of robots in warehouses is an example of digital communication influencing operations."}'::jsonb, '{"answer": true, "explain": "Correct. Once an order is received, it is communicated digitally to a robot which retrieves the product. This has automated operations, reduced errors, sped up dispatch, and reduced labour costs — all impacts of digital communication on business operations."}'::jsonb),
('business:3-3-communication-in-business:learn:a6f21713', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'learn', 'mcq', 1, '{"readingTitle": "Core Terminology", "reading": "<ul>\n<li><strong>Communication</strong> — the transmission of a message from a sender to a receiver through a means of communication</li>\n<li><strong>Verbal communication</strong> — communicating by speaking: in meetings, on the telephone, by video-conferencing, or through a presentation</li>\n<li><strong>Written communication</strong> — communication by written words: text, email, and letters</li>\n<li><strong>Digital communication</strong> — the electronic exchange of information using ICT (voice, text, diagrams, pictures, video)</li>\n<li><strong>Feedback</strong> — the response made by a person who receives a communication, indicating they have (or have not) understood it</li>\n<li><strong>Internal communication</strong> — communication between people employed in the same organisation</li>\n<li><strong>External communication</strong> — communication between people in an organisation and others outside it</li>\n<li><strong>Formal communication</strong> — communication through official channels (e.g. letters, official meetings, reports)</li>\n<li><strong>Informal communication</strong> — communication outside official channels (e.g. conversations in a break)</li>\n<li><strong>Social media</strong> — online applications that allow people to create and share content to participate in social networking</li>\n<li><strong>Website</strong> — an online location with several pages that can be contacted by internet users through its address</li>\n</ul>", "question": "Which term describes communication between people employed in the same organisation?", "options": ["Internal communication", "Feedback", "Formal communication", "External communication"]}'::jsonb, '{"answer": 0, "explain": "Internal communication is defined as communication between people employed in the same organisation, unlike external communication which involves people outside it."}'::jsonb),
('business:3-3-communication-in-business:learn:7cace3f2', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'learn', 'mcq', 1, '{"readingTitle": "One-way, Two-way & Direction of Communication", "reading": "<p><strong>One-way communication:</strong> the message is sent but there is no reply. Good for giving information to large numbers of people (e.g. a tannoy announcement, an advertising leaflet). Examples: email broadcast, website, social media post.</p>\n<p><strong>Two-way communication:</strong> the receiver can reply to the sender. Important because:</p>\n<ul>\n<li>Feedback confirms the message has been received and understood</li>\n<li>It is good for generating ideas and solving problems</li>\n</ul>\n<p><strong>Vertical communication:</strong> between people on different layers of the hierarchy — either downward (manager to worker) or upward (worker to manager).</p>\n<p><strong>Horizontal communication:</strong> between people at the same level within the organisation structure (e.g. two managers in different departments).</p>\n<p><strong>Internal vs External:</strong> Internal = within the organisation. External = between someone inside the organisation and someone outside it (e.g. a supplier, customer, or government body).</p>", "question": "Communication between two managers who work at the same level in different departments is an example of which type of communication?", "options": ["Vertical communication", "One-way communication", "External communication", "Horizontal communication"]}'::jsonb, '{"answer": 3, "explain": "Horizontal communication takes place between people at the same level within the organisation structure, whereas vertical communication moves up or down the hierarchy."}'::jsonb),
('business:3-3-communication-in-business:learn:cba74c78', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'learn', 'mcq', 1, '{"readingTitle": "Verbal Communication — Methods, Advantages & Disadvantages", "reading": "<p><strong>Examples:</strong> phone calls, meetings (in person or via Teams/Zoom), presentations</p>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">✓ Advantages</div>\n<div class=\"pro-item\">Can check the message has been understood by asking for feedback immediately</div>\n<div class=\"pro-item\">Tone of voice and body language can emphasise key points</div>\n<div class=\"pro-item\">Can use diagrams, pictures, slides to support the message</div>\n<div class=\"pro-item\">Meetings — minutes provide a record; ideas can be generated and problems solved</div>\n</div>\n<div>\n<div class=\"col-head\">✗ Disadvantages</div>\n<div class=\"con-item\">No permanent record (unless minutes taken or recording made)</div>\n<div class=\"con-item\">With large audiences, hard to check everyone has heard or understood</div>\n<div class=\"con-item\">Receiver may disrupt or interrupt the message</div>\n<div class=\"con-item\">Some forms (e.g. travel for international meetings) can be expensive</div>\n</div>\n</div>\n<p style=\"margin-top:10px;\"><strong>Meetings</strong> can be formal (with an agenda and chairperson) or informal (impromptu, no agenda). Online meetings via Teams or Zoom save travel costs.</p>\n<p><strong>Presentations</strong> may use PowerPoint to support visual explanation; the speaker can respond to questions.</p>", "question": "What is a key disadvantage of verbal communication such as a phone call or meeting?", "options": ["There is usually no permanent record unless minutes are taken", "Feedback cannot be given immediately", "It is never a suitable method for solving business problems", "It cannot use tone of voice to emphasise key points"]}'::jsonb, '{"answer": 0, "explain": "The card lists the lack of a permanent record (unless minutes are taken or a recording made) as a disadvantage of verbal communication."}'::jsonb),
('business:3-3-communication-in-business:learn:9c2099a4', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'learn', 'mcq', 1, '{"readingTitle": "Written Communication — Letters, Emails, Texts", "reading": "<p><strong>Letters:</strong> formal, provide a physical record; can be sent by recorded delivery; often used for contracts or legal documents.</p>\n<p><strong>Emails and texts:</strong> fast, widely used; can be sent to one or many people; disadvantage is that bulk emails are often ignored or sent to spam.</p>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">✓ Advantages of Written</div>\n<div class=\"pro-item\">There is a record of the message</div>\n<div class=\"pro-item\">Receiver can read and re-read to check understanding</div>\n<div class=\"pro-item\">Can be sent to multiple people at once</div>\n<div class=\"pro-item\">Can avoid confrontation</div>\n<div class=\"pro-item\">Text and email are very fast</div>\n</div>\n<div>\n<div class=\"col-head\">✗ Disadvantages of Written</div>\n<div class=\"con-item\">Cannot immediately check receiver has understood</div>\n<div class=\"con-item\">Success depends on how clearly it has been written</div>\n<div class=\"con-item\">Risk of virus infection from email attachments</div>\n<div class=\"con-item\">Emails can get lost in spam</div>\n<div class=\"con-item\">Some people get overwhelmed by volume of emails</div>\n</div>\n</div>", "question": "Which of these is a specific advantage of written communication compared with verbal communication?", "options": ["It allows the sender to check understanding immediately", "It is always cheaper than any other method", "Tone of voice can be used to emphasise key points", "It leaves a permanent record the receiver can re-read"]}'::jsonb, '{"answer": 3, "explain": "The card states that written communication leaves a record of the message and lets the receiver read and re-read it to check understanding, unlike verbal communication."}'::jsonb)
